const event = $json.body?.entry?.[0]?.messaging?.[0] || {};
const rawText = ($json.text || event.message?.text || event.postback?.title || event.postback?.payload || '').toString().trim();
const text = rawText.toLowerCase().normalize('NFC');

const normalized = text
  .replace(/[.,!?;:]+$/g, '')
  .replace(/\s+/g, ' ')
  .replace(/^số\s+/, '')
  .trim();

const removeTone = (value) => value
  .toString()
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/đ/g, 'd')
  .replace(/\s+/g, ' ')
  .trim();

const key = removeTone(normalized);

const categoryMap = {
  '1': 'Áo',
  'ao': 'Áo',
  '2': 'Quần',
  'quan': 'Quần',
  '3': 'Váy',
  'vay': 'Váy',
  '4': 'Phụ kiện',
  'phu kien': 'Phụ kiện'
};

const greetingSet = new Set([
  'hi', 'hello', 'xin chao', 'chao', 'chao shop', 'menu', 'tu van',
  'bat dau', 'start', 'alo', 'shop oi', 'ministyle'
]);

let intent = 'ai';
let category = '';

if (!rawText) {
  intent = 'menu';
} else if (categoryMap[key]) {
  intent = 'category';
  category = categoryMap[key];
} else if (greetingSet.has(key)) {
  intent = 'menu';
}

return {
  ...$json,
  raw_text: rawText,
  normalized_text: normalized,
  normalized_key: key,
  intent,
  category
};

const source = $('Normalize Text').item.json;
const category = source.category;
const rows = $input.all().map(item => item.json);

const normalize = (value) => (value || '')
  .toString()
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/đ/g, 'd')
  .replace(/\s+/g, ' ')
  .trim();

const wanted = normalize(category);
const products = rows.filter(row => {
  const rowCategory = normalize(row['Danh mục'] || row['Danh Mục'] || row['Danh muc']);
  const rowType = normalize(row['Phân loại'] || row['Phan loai'] || row['Loại']);
  return rowCategory === wanted || rowType === wanted;
});

let message = '';

if (products.length === 0) {
  const availableCategories = [...new Set(rows.map(row => row['Danh mục'] || row['Danh Mục'] || row['Phân loại']).filter(Boolean))].join(', ');
  message = 'MiniStyle chưa tìm thấy sản phẩm thuộc danh mục ' + category + '.\n\n'
    + 'Các danh mục đang đọc được: ' + (availableCategories || 'chưa có dữ liệu') + '.\n\n'
    + 'Anh/chị có thể nhập menu để xem lại danh mục.';
} else {
  const icon = category === 'Áo' ? '👕' : category === 'Quần' ? '👖' : category === 'Váy' ? '👗' : '🧢';
  message = icon + ' ' + category + '\n\n';

  products.slice(0, 20).forEach((row, index) => {
    const name = row['Tên Sản Phẩm'] || row['Tên sản phẩm'] || row['Sản Phẩm'] || row['Ten san pham'] || ('Sản phẩm ' + (index + 1));
    const price = row['Giá'] || row['Giá bán'] || row['Gia'] || '';
    const sold = row['Đã bán'] || row['Da ban'] || '';
    message += (index + 1) + '. ' + name + (price ? ' - ' + price : '') + (sold ? ' · Đã bán: ' + sold : '') + '\n';
  });

  if (products.length > 20) {
    message += '\nMiniStyle còn ' + (products.length - 20) + ' sản phẩm khác trong danh mục này.';
  }

  message += '\nAnh/chị có thể nhập tên sản phẩm để xem chi tiết, giá, màu, size hoặc ảnh.';
}

return {
  ...source,
  products,
  message
};

