const source = $('Normalize Text').item.json;
const rows = $input.all().map(item => item.json);

const clean = (value) => value === undefined || value === null ? '' : String(value).trim();
const products = rows.map((row, index) => ({
  stt: clean(row['STT'] || row['stt'] || index + 1),
  name: clean(row['Tên Sản Phẩm'] || row['Tên sản phẩm'] || row['Sản Phẩm'] || row['Ten san pham']),
  category: clean(row['Danh mục'] || row['Danh Mục'] || row['Danh muc'] || row['Phân loại']),
  type: clean(row['Phân loại'] || row['Phan loai']),
  price: clean(row['Giá'] || row['Giá bán'] || row['Gia']),
  sold: clean(row['Đã bán'] || row['Da ban']),
  colors: clean(row['Màu'] || row['Màu sắc'] || row['Mau'] || row['Mau sac']),
  sizes: clean(row['Size'] || row['Kích thước'] || row['Kich thuoc']),
  image: clean(row['URL ảnh'] || row['URL Ảnh'] || row['Image'] || row['Ảnh']),
  attachment_id: clean(row['ID Ảnh'] || row['Attachment ID'])
})).filter(product => product.name);

const compactProducts = products.slice(0, 80);
const aiInput = [
  'Tin nhắn khách hàng:',
  source.raw_text || '',
  '',
  'Dữ liệu sản phẩm MiniStyle từ Google Sheet:',
  JSON.stringify(compactProducts, null, 2),
  '',
  'Chính sách shop:',
  '- Giao hàng toàn quốc từ 2-4 ngày làm việc. Miễn phí vận chuyển cho đơn từ 500.000đ nếu shop đang áp dụng.',
  '- Đổi size trong 7 ngày nếu sản phẩm còn tem mác và chưa qua sử dụng.',
  '- Đặt hàng bằng cách cung cấp sản phẩm, màu, size, số lượng, họ tên, số điện thoại và địa chỉ nhận hàng.'
].join('\n');

return {
  ...source,
  products: compactProducts,
  ai_input: aiInput
};
